1	export function scalePixelArt(image: string[][], scale: number): string[][] {
2	  return image.flatMap(row => {
3	    const scaledRow = row.flatMap(pixel => Array(scale).fill(pixel));
4	    return Array(scale).fill(scaledRow);
5	  });
6	}
